    float* data_buffer = new float[packet->data_length];

    for (int i = 0; i < packet->data_length; ++i) {
        data_buffer[i] = transform_data(packet->raw_values[i]);
    }

    // Send to telemetry service
    if (!telemetry_service.send(data_buffer, packet->data_length)) {
